select jobid, version, stepid, stepname, steptype, stepseq, db, status, phase, threadcnt, commitcnt,  DATE_FORMAT(enddate,'%Y/%m/%d') as enddate,  DATE_FORMAT(regdate,'%Y/%m/%d') as regdate,  DATE_FORMAT(upddate,'%Y/%m/%d') as upddate, reguserid, upduserid, data_handling_method, processing_method, fk_disable_flag, index_unusual_flag, val1, val2, val3, val4, val5
